# Adaptive threshold: step down the score threshold if no results are found.
# Avoids empty-handed responses for valid but loosely-phrased queries.

def retrieve_with_fallback(
    query: str,
    collection: str,
    thresholds: list[float] | None = None,
    user_id: str | None = None,
) -> list[dict]:
    if thresholds is None:
        thresholds = [0.80, 0.72, 0.60, 0.50]

    vec = embed_query(query)
    for threshold in thresholds:
        results = ann_search(vec, collection, score_threshold=threshold, user_id=user_id)
        if results:
            return results
    return []  # nothing found even at lowest threshold

# Usage
results = retrieve_with_fallback("project timeline", "memories", user_id="u42")
if results:
    top = rerank_candidates("project timeline", results)
    answer = format_memory_block(top[:5])
else:
    answer = ""  # no memory available — answer from model knowledge only
